/*
  feral/ui — controlled variance system
  The brand is rude. The implementation is not.

  Law:
  1. Ink stays authoritative.
  2. Pressure is universal.
  3. Variance is tokenized, not random.
  4. Humor is allowed. Fake accessibility is not.
*/

:root {
  color-scheme: light;
  --feral-ink: #0a0a0a;
  --feral-cream: #fff4e0;
  --feral-bone: #fff9f0;
  --feral-paper: #ffffff;
  --feral-muted: #5f5a52;
  --feral-pink: #ff2d9b;
  --feral-acid: #bfff00;
  --feral-ultra: #3d2bff;
  --feral-verm: #ff3b1d;
  --feral-cyan: #00e5ff;
  --feral-violet: #9747ff;
  --feral-tang: #ff8a00;
  --feral-sky: #74b9ff;

  --feral-radius-none: 0px;
  --feral-radius-sm: 6px;
  --feral-radius-md: 10px;
  --feral-radius-lg: 16px;
  --feral-radius-pill: 999px;

  --feral-border-xs: 2px;
  --feral-border-sm: 3px;
  --feral-border-md: 4px;
  --feral-border-lg: 5px;
  --feral-border-xl: 6px;

  --feral-pressure-sm: 3px;
  --feral-pressure-md: 5px;
  --feral-pressure-lg: 7px;
  --feral-pressure-xl: 9px;

  --feral-focus: var(--feral-ultra);
  --feral-speed: 80ms;
  --feral-font-display: "Bricolage Grotesque", ui-sans-serif, system-ui, sans-serif;
  --feral-font-monoish: "Space Grotesk", ui-sans-serif, system-ui, sans-serif;
}

* { box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  margin: 0;
  min-width: 320px;
  font-family: var(--feral-font-display);
  color: var(--feral-ink);
  background: var(--feral-cream);
  background-image: radial-gradient(var(--feral-ink) .75px, transparent .75px);
  background-size: 22px 22px;
}

button, input, textarea, select { font: inherit; }
a { color: inherit; }
::selection { background: var(--feral-pink); color: white; }

.feral-shell { min-height: 100vh; }
.feral-page { max-width: 1180px; margin: 0 auto; padding: 0 20px; }
.feral-sr-only { position:absolute; width:1px; height:1px; padding:0; margin:-1px; overflow:hidden; clip:rect(0,0,0,0); white-space:nowrap; border:0; }
.feral-skip {
  position: absolute;
  top: 8px;
  left: 8px;
  z-index: 999;
  padding: 10px 14px;
  background: var(--feral-acid);
  border: var(--feral-border-sm) solid var(--feral-ink);
  transform: translateY(-140%);
}
.feral-skip:focus { transform: translateY(0); }

/* Utility primitives */
.feral-press {
  --feral-x: 0px;
  --feral-y: 0px;
  --feral-tilt: 0deg;
  --feral-shadow-x: var(--feral-pressure-md);
  --feral-shadow-y: var(--feral-pressure-md);
  --feral-shadow-color: var(--feral-ink);
  transform: translate(var(--feral-x), var(--feral-y)) rotate(var(--feral-tilt));
  transition: transform var(--feral-speed) linear, box-shadow var(--feral-speed) linear;
}
.feral-press:hover { --feral-x: 2px; --feral-y: 2px; }
.feral-press:active { --feral-x: var(--feral-shadow-x); --feral-y: var(--feral-shadow-y); box-shadow: 0 0 0 0 var(--feral-shadow-color) !important; }

.feral-focus-ring:focus-visible,
.feral-focus-ring :where(button,input,textarea,select,a):focus-visible {
  outline: 3px dashed var(--feral-focus);
  outline-offset: 3px;
}

.feral-pattern-dots { background-image: radial-gradient(var(--feral-ink) 1.4px, transparent 1.4px); background-size: 10px 10px; }
.feral-pattern-stripes { background-image: repeating-linear-gradient(45deg, transparent 0 7px, rgba(10,10,10,.25) 7px 8px); }
.feral-pattern-check { background-image: repeating-conic-gradient(rgba(10,10,10,.18) 0% 25%, transparent 0% 50%); background-size: 14px 14px; }
.feral-pattern-zap { background-image: linear-gradient(135deg,var(--feral-pink) 25%,transparent 25%),linear-gradient(225deg,var(--feral-acid) 25%,transparent 25%),linear-gradient(315deg,var(--feral-ultra) 25%,transparent 25%),linear-gradient(45deg,var(--feral-tang) 25%,transparent 25%); background-size: 22px 22px; }

/* Components */
.feral-button {
  --feral-bg: var(--feral-acid);
  --feral-fg: var(--feral-ink);
  --feral-radius: var(--feral-radius-md);
  --feral-border: var(--feral-border-md);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  min-height: 44px;
  padding: 11px 18px;
  cursor: pointer;
  user-select: none;
  text-decoration: none;
  color: var(--feral-fg);
  background: var(--feral-bg);
  border: var(--feral-border) solid var(--feral-ink);
  border-radius: var(--feral-radius);
  box-shadow: var(--feral-shadow-x) var(--feral-shadow-y) 0 0 var(--feral-shadow-color);
  font-weight: 800;
  letter-spacing: -0.01em;
}
.feral-button[data-tone="pink"] { --feral-bg: var(--feral-pink); --feral-fg: #fff; --feral-shadow-color: var(--feral-ink); }
.feral-button[data-tone="ultra"] { --feral-bg: var(--feral-ultra); --feral-fg: #fff; --feral-shadow-color: var(--feral-pink); }
.feral-button[data-tone="ink"] { --feral-bg: var(--feral-ink); --feral-fg: var(--feral-cream); --feral-shadow-color: var(--feral-pink); }
.feral-button[data-tone="paper"] { --feral-bg: var(--feral-paper); --feral-fg: var(--feral-ink); --feral-shadow-color: var(--feral-ink); }
.feral-button[data-tone="tang"] { --feral-bg: var(--feral-tang); --feral-fg: var(--feral-ink); --feral-shadow-color: var(--feral-ultra); }
.feral-button[data-shape="square"] { --feral-radius: var(--feral-radius-none); }
.feral-button[data-shape="pill"] { --feral-radius: var(--feral-radius-pill); }
.feral-button[data-size="sm"] { min-height: 36px; padding: 8px 13px; font-size: 13px; --feral-border: var(--feral-border-sm); }
.feral-button[data-size="lg"] { min-height: 54px; padding: 14px 24px; font-size: 18px; --feral-border: var(--feral-border-lg); }
.feral-button[disabled], .feral-button[aria-disabled="true"] { opacity: .55; cursor: not-allowed; }

.feral-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  border: var(--feral-border-sm) solid var(--feral-ink);
  border-radius: var(--feral-radius-none);
  background: var(--feral-acid);
  color: var(--feral-ink);
  font: 800 12px/1 var(--feral-font-display);
  letter-spacing: .04em;
  text-transform: uppercase;
}
.feral-badge[data-tone="pink"] { background: var(--feral-pink); color: #fff; border-radius: var(--feral-radius-pill); box-shadow: 3px 3px 0 var(--feral-ink); }
.feral-badge[data-tone="ultra"] { background: var(--feral-ultra); color: #fff; border-radius: var(--feral-radius-sm); transform: rotate(-2deg); }
.feral-badge[data-tone="paper"] { background: var(--feral-paper); border-style: dashed; }
.feral-badge[data-tone="tang"] { background: var(--feral-tang); border-radius: var(--feral-radius-pill); }

.feral-card {
  --feral-card-bg: var(--feral-paper);
  --feral-card-radius: var(--feral-radius-lg);
  --feral-card-border: var(--feral-border-md);
  --feral-shadow-color: var(--feral-ink);
  position: relative;
  background: var(--feral-card-bg);
  border: var(--feral-card-border) solid var(--feral-ink);
  border-radius: var(--feral-card-radius);
  box-shadow: var(--feral-shadow-x) var(--feral-shadow-y) 0 var(--feral-shadow-color);
}
.feral-card[data-tone="acid"] { --feral-card-bg: var(--feral-acid); --feral-card-radius: var(--feral-radius-none); }
.feral-card[data-tone="pink"] { --feral-card-bg: var(--feral-pink); color:#fff; --feral-shadow-color: var(--feral-ultra); }
.feral-card[data-tone="ultra"] { --feral-card-bg: var(--feral-ultra); color:#fff; --feral-shadow-color: var(--feral-acid); --feral-card-radius: var(--feral-radius-none); }
.feral-card[data-tone="tang"] { --feral-card-bg: var(--feral-tang); --feral-shadow-color: var(--feral-ultra); }
.feral-card[data-radius="none"] { --feral-card-radius: var(--feral-radius-none); }
.feral-card[data-radius="pill"] { --feral-card-radius: var(--feral-radius-pill); }
.feral-card-header { padding: 20px 20px 0; }
.feral-card-title { margin: 0; font-size: 18px; line-height: 1.05; letter-spacing: -.02em; }
.feral-card-description { margin: 6px 0 0; color: rgba(10,10,10,.68); font-family: var(--feral-font-monoish); font-size: 13px; }
.feral-card[data-tone="pink"] .feral-card-description,
.feral-card[data-tone="ultra"] .feral-card-description { color: rgba(255,255,255,.78); }
.feral-card-content { padding: 20px; }
.feral-card-footer { padding: 0 20px 20px; display: flex; gap: 10px; flex-wrap: wrap; }

.feral-alert {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 14px 18px;
  border: var(--feral-border-sm) solid var(--feral-ink);
  border-radius: var(--feral-radius-pill);
  background: var(--feral-ultra);
  color: #fff;
  box-shadow: var(--feral-shadow-x) var(--feral-shadow-y) 0 var(--feral-shadow-color);
  font-weight: 700;
}
.feral-alert[data-tone="acid"] { background: var(--feral-acid); color: var(--feral-ink); border-radius: var(--feral-radius-md); }
.feral-alert[data-tone="pink"] { background: var(--feral-pink); color:#fff; --feral-shadow-color: var(--feral-ultra); }
.feral-alert-icon { flex: none; font-size: 19px; line-height: 1; }
.feral-alert-title { font-weight: 800; }
.feral-alert-description { margin-top: 2px; font: 500 13px/1.45 var(--feral-font-monoish); opacity: .86; }

.feral-label { display: inline-flex; margin-bottom: 6px; font-weight: 800; font-size: 13px; }
.feral-input,
.feral-textarea,
.feral-select {
  width: 100%;
  min-height: 44px;
  padding: 10px 12px;
  background: #fff;
  color: var(--feral-ink);
  border: var(--feral-border-sm) solid var(--feral-ink);
  border-radius: var(--feral-radius-none);
  box-shadow: 4px 4px 0 var(--feral-ink);
  font-family: var(--feral-font-monoish);
  font-weight: 600;
}
.feral-textarea { min-height: 110px; resize: vertical; line-height: 1.45; }
.feral-input:focus,
.feral-textarea:focus,
.feral-select:focus { outline: none; border-color: var(--feral-focus); box-shadow: 4px 4px 0 var(--feral-focus); }
.feral-field { display: grid; gap: 4px; }
.feral-field-help { margin: 0; font: 500 12px/1.45 var(--feral-font-monoish); color: var(--feral-muted); }

.feral-checkbox-row,
.feral-radio-row,
.feral-switch-row { display: inline-flex; align-items: center; gap: 10px; font-weight: 800; cursor: pointer; }
.feral-checkbox,
.feral-radio {
  appearance: none;
  width: 24px;
  height: 24px;
  flex: none;
  background: #fff;
  border: var(--feral-border-sm) solid var(--feral-ink);
  position: relative;
  cursor: pointer;
}
.feral-radio { border-radius: 50%; }
.feral-checkbox:checked { background: var(--feral-ink); }
.feral-checkbox:checked::after { content: "✕"; position: absolute; inset: 0; display: grid; place-items: center; color: #fff; font-weight: 900; font-size: 13px; }
.feral-radio:checked::after { content: ""; position: absolute; inset: 4px; border-radius: 50%; background: var(--feral-pink); }

.feral-switch { position: relative; display: inline-grid; width: 64px; height: 36px; flex: none; }
.feral-switch input { position:absolute; inset:0; opacity:0; cursor:pointer; }
.feral-switch-track { position:absolute; inset:0; border: var(--feral-border-sm) solid var(--feral-ink); border-radius: var(--feral-radius-pill); background: var(--feral-paper); box-shadow: 3px 3px 0 var(--feral-ink); }
.feral-switch-track::before { content:""; position:absolute; inset:0; border-radius: inherit; background: repeating-linear-gradient(45deg, transparent 0 5px, rgba(10,10,10,.18) 5px 6px); }
.feral-switch-thumb { position:absolute; top: 6px; left: 6px; width: 20px; height: 20px; border-radius: 50%; border: var(--feral-border-xs) solid var(--feral-ink); background: #fff; transition: left var(--feral-speed) linear; }
.feral-switch input:checked ~ .feral-switch-track { background: var(--feral-acid); }
.feral-switch input:checked ~ .feral-switch-thumb { left: 38px; }

.feral-accordion { display: grid; gap: 10px; }
.feral-accordion details { border: var(--feral-border-md) solid var(--feral-ink); border-radius: var(--feral-radius-lg); background:#fff; box-shadow: 5px 5px 0 var(--feral-violet); overflow: hidden; }
.feral-accordion summary { cursor: pointer; list-style: none; padding: 14px 18px; background: var(--feral-violet); color: #fff; font-weight: 800; display: flex; justify-content: space-between; gap: 12px; }
.feral-accordion summary::-webkit-details-marker { display:none; }
.feral-accordion summary::after { content:"+"; font-size: 22px; line-height: .8; }
.feral-accordion details[open] summary::after { content:"−"; }
.feral-accordion-panel { padding: 15px 18px; line-height: 1.55; color:#333; }

.feral-tabs { border: var(--feral-border-sm) solid var(--feral-ink); border-radius: var(--feral-radius-lg); background:#fff; box-shadow:5px 5px 0 var(--feral-tang); padding: 18px; }
.feral-tab-list { display:flex; border: var(--feral-border-sm) solid var(--feral-ink); border-radius: var(--feral-radius-md); overflow:hidden; margin-bottom: 14px; }
.feral-tab { flex:1; border:0; padding: 10px 12px; font-weight: 900; cursor:pointer; background:#fff; border-bottom: 0 solid transparent; }
.feral-tab:nth-child(1) { background: var(--feral-acid); }
.feral-tab:nth-child(2) { background: var(--feral-pink); color:#fff; }
.feral-tab:nth-child(3) { background: var(--feral-cyan); }
.feral-tab[aria-selected="true"] { box-shadow: inset 0 -6px 0 var(--feral-ink); }
.feral-tab-panel { font: 500 14px/1.55 var(--feral-font-monoish); color:#333; }

.feral-otp { display:flex; gap: 8px; flex-wrap: wrap; }
.feral-otp input { width: 44px; height: 52px; text-align:center; font-size: 22px; font-weight:900; border: var(--feral-border-sm) solid var(--feral-ink); box-shadow: 3px 3px 0 var(--feral-ink); background:#fff; }
.feral-otp input:nth-child(1) { background: var(--feral-acid); }
.feral-otp input:nth-child(2) { background: var(--feral-pink); color:#fff; }
.feral-otp input:nth-child(3) { background: var(--feral-cyan); }
.feral-otp input:nth-child(4) { background: var(--feral-tang); }
.feral-otp input:nth-child(5) { background: var(--feral-violet); color:#fff; }
.feral-otp input:nth-child(6) { background: var(--feral-paper); }
.feral-otp input:focus { outline:none; box-shadow: 3px 3px 0 var(--feral-focus); border-color: var(--feral-focus); }

.feral-pagination { display:flex; align-items:center; gap:6px; flex-wrap:wrap; }
.feral-page-button { width: 38px; height:38px; border: var(--feral-border-sm) solid var(--feral-ink); background:#fff; color: var(--feral-ink); font-weight:900; cursor:pointer; }
.feral-page-button:nth-child(1), .feral-page-button:nth-last-child(1) { border-radius: 50%; }
.feral-page-button[data-active="true"] { background: var(--feral-pink); color:#fff; box-shadow: 3px 3px 0 var(--feral-ink); border-radius: var(--feral-radius-md); }

.feral-marquee { overflow:hidden; white-space:nowrap; border-block: var(--feral-border-sm) solid var(--feral-ink); background:var(--feral-ink); color: var(--feral-cream); }
.feral-marquee-track { display:inline-block; padding: 12px 0; animation: feral-marquee 22s linear infinite; font-weight:900; letter-spacing:.05em; }
.feral-marquee span { margin: 0 24px; }
@keyframes feral-marquee { to { transform: translateX(-50%); } }

/* Site */
.site-nav { position: sticky; top:0; z-index:20; display:flex; align-items:center; gap:8px; min-height:58px; padding: 0 16px; border-bottom: var(--feral-border-sm) solid var(--feral-ink); background: var(--feral-acid); overflow-x:auto; }
.site-mark { display:inline-flex; align-items:center; gap:8px; font-weight:900; font-size:20px; white-space:nowrap; margin-right: 12px; }
.site-mark-dot { width:24px; height:24px; border-radius:50%; background: var(--feral-pink); border: var(--feral-border-sm) solid var(--feral-ink); transform: rotate(-14deg); }
.site-nav a, .site-nav button { border:0; background:transparent; color:var(--feral-ink); text-decoration:none; font-weight:800; padding: 8px 10px; border-radius: var(--feral-radius-sm); white-space:nowrap; cursor:pointer; }
.site-nav a:hover, .site-nav button:hover { background: var(--feral-ink); color: var(--feral-acid); }
.site-nav-right { margin-left:auto; display:flex; align-items:center; gap:8px; }
.site-search { border: var(--feral-border-xs) solid var(--feral-ink); border-radius: var(--feral-radius-pill); background:#fff; padding: 7px 12px; font: 700 12px var(--feral-font-monoish); color: var(--feral-muted); }
.site-hero { padding: 66px 20px 10px; text-align:center; max-width: 1180px; margin:0 auto; }
.site-eyebrow { display:inline-flex; gap:8px; align-items:center; margin-bottom:16px; }
.site-hero h1 { margin:0; font-size: clamp(46px, 8vw, 104px); line-height:.91; letter-spacing: -.045em; }
.site-highlight { display:inline-block; padding: 0 14px; border: var(--feral-border-md) solid var(--feral-ink); box-shadow: 6px 6px 0 var(--feral-ink); }
.site-highlight.pink { background: var(--feral-pink); color:#fff; border-radius: var(--feral-radius-md); transform: rotate(-2deg); }
.site-highlight.acid { background: var(--feral-acid); border-radius: var(--feral-radius-none); box-shadow:6px 6px 0 var(--feral-ultra); transform: rotate(1.5deg); }
.site-highlight.cyan { background: var(--feral-cyan); border-radius: var(--feral-radius-pill); box-shadow:6px 6px 0 var(--feral-pink); transform: rotate(-1deg); }
.site-hero p { max-width: 62ch; margin: 24px auto 0; font-size: 18px; line-height:1.58; color:#333; }
.site-hero-actions { margin-top: 26px; display:flex; justify-content:center; gap:14px; flex-wrap:wrap; }
.site-note { margin: 24px auto 0; max-width: 720px; border: var(--feral-border-sm) dashed var(--feral-ink); background:#fff; padding: 13px 16px; font: 700 13px/1.45 var(--feral-font-monoish); }
.site-collage { max-width: 1280px; margin: 34px auto 0; padding: 0 16px; columns:4; column-gap: 18px; }
.site-collage > * { break-inside: avoid; margin-bottom:18px; }
.site-section { max-width: 1120px; margin:0 auto; padding: 72px 20px 0; }
.site-section h2 { margin:0; font-size: clamp(30px, 4.2vw, 48px); letter-spacing:-.035em; line-height:1; }
.site-section-intro { margin: 10px 0 0; max-width: 68ch; color:#333; font-size:16px; line-height:1.55; }
.site-grid { display:grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 20px; margin-top: 28px; }
.site-code { display:block; overflow:auto; white-space:pre; padding: 16px; background: var(--feral-ink); color: var(--feral-acid); border: var(--feral-border-sm) solid var(--feral-ink); box-shadow: 5px 5px 0 var(--feral-pink); font: 700 12px/1.55 var(--feral-font-monoish); }
.site-table { width:100%; border-collapse: collapse; background:#fff; box-shadow: 6px 6px 0 var(--feral-ink); }
.site-table th, .site-table td { border: var(--feral-border-xs) solid var(--feral-ink); padding: 12px; text-align:left; vertical-align:top; }
.site-table th { background: var(--feral-acid); font-weight:900; }
.site-footer { max-width:1120px; margin:80px auto 0; padding: 22px 20px 60px; border-top: var(--feral-border-sm) solid var(--feral-ink); display:flex; justify-content:space-between; gap:16px; flex-wrap:wrap; font:700 12px var(--feral-font-monoish); color: var(--feral-muted); }
.site-fake-quotes { border: var(--feral-border-sm) dashed var(--feral-ink); background: #fff; padding: 14px; font: 800 13px var(--feral-font-monoish); }

@media (max-width: 1050px) { .site-collage { columns: 3; } }
@media (max-width: 820px) { .site-collage { columns: 2; } .site-nav-right { display:none; } }
@media (max-width: 560px) { .site-collage { columns: 1; } .site-hero { padding-top: 42px; } }
@media (prefers-reduced-motion: reduce) { *, *::before, *::after { animation-duration: .001ms !important; animation-iteration-count: 1 !important; scroll-behavior:auto !important; transition:none !important; } }

/* v0.2 Radix-backed overlay/navigation layer */
.feral-dialog-overlay {
  position: fixed;
  inset: 0;
  z-index: 80;
  background:
    radial-gradient(var(--feral-ink) 1px, transparent 1px),
    rgba(10, 10, 10, .62);
  background-size: 12px 12px, auto;
}
.feral-dialog-content,
.feral-sheet-content {
  position: fixed;
  z-index: 90;
  background: var(--feral-bone);
  color: var(--feral-ink);
  border: var(--feral-border-lg) solid var(--feral-ink);
  box-shadow: var(--feral-pressure-lg) var(--feral-pressure-lg) 0 var(--feral-pink), calc(var(--feral-pressure-lg) * 2) calc(var(--feral-pressure-lg) * 2) 0 var(--feral-ultra);
  padding: 24px;
}
.feral-dialog-content {
  left: 50%;
  top: 50%;
  width: min(calc(100vw - 32px), 560px);
  transform: translate(-50%, -50%) rotate(var(--feral-tilt));
  border-radius: var(--feral-radius-lg);
}
.feral-dialog-content.feral-press:hover { --feral-x: 0px; --feral-y: 0px; }
