.feral-table-wrap { overflow:auto; border: var(--feral-border-sm) solid var(--feral-ink); box-shadow: 5px 5px 0 var(--feral-ink); background:#fff; }
.feral-table { width: 100%; border-collapse: collapse; min-width: 520px; }
