/* v0.3 parity components, blocks, and docs surfaces */
.feral-avatar { display:inline-flex; width:48px; height:48px; overflow:hidden; align-items:center; justify-content:center; border:var(--feral-border-sm) solid var(--feral-ink); border-radius:50%; background:var(--feral-acid); box-shadow:4px 4px 0 var(--feral-ink); font-weight:900; }
