.feral-toggle[data-tone="acid"]{background:var(--feral-acid)}.feral-toggle[data-tone="pink"]{background:var(--feral-pink); color:#fff}.feral-toggle[data-tone="ultra"]{background:var(--feral-ultra); color:#fff}.feral-toggle[data-tone="paper"]{background:var(--feral-paper)}
