.feral-timeline-item[data-tone="pink"] time{background:var(--feral-pink); color:#fff}.feral-timeline-item[data-tone="ultra"] time{background:var(--feral-ultra); color:#fff}.feral-timeline-item[data-tone="tang"] time{background:var(--feral-tang)}
