.feral-theme-swatch[data-tone="acid"]{background:var(--feral-acid)}.feral-theme-swatch[data-tone="pink"]{background:var(--feral-pink); color:#fff}.feral-theme-swatch[data-tone="ultra"]{background:var(--feral-ultra); color:#fff}.feral-theme-swatch[data-tone="tang"]{background:var(--feral-tang)}.feral-theme-swatch[data-tone="cyan"]{background:var(--feral-cyan)}
