.feral-image-card figcaption { display:grid; gap:2px; padding:12px; border-top:var(--feral-border-xs) solid var(--feral-ink); }
.feral-image-card figcaption span { font-size:12px; color:#3b342e; }
.feral-banner { display:flex; justify-content:space-between; gap:12px; align-items:center; padding:12px 16px; border:var(--feral-border-sm) solid var(--feral-ink); background:var(--feral-acid); box-shadow:5px 5px 0 var(--feral-ink); font-weight:900; }
.feral-banner[data-tone="pink"]{background:var(--feral-pink); color:#fff}.feral-banner[data-tone="ultra"]{background:var(--feral-ultra); color:#fff}.feral-banner[data-tone="tang"]{background:var(--feral-tang)}.feral-banner[data-tone="paper"]{background:var(--feral-paper)}
.feral-avatar-group { display:flex; align-items:center; }
.feral-avatar-group .feral-avatar { margin-left:-10px; box-shadow:3px 3px 0 var(--feral-ink); }
.feral-avatar-group .feral-avatar:first-child { margin-left:0; }
.site-product-panel { display:grid; grid-template-columns:1fr 1fr; gap:18px; margin-top:24px; }
.site-product-panel .feral-card { align-content:start; }
.site-metric-strip { display:grid; grid-template-columns:repeat(4,minmax(0,1fr)); gap:12px; margin-top:24px; }
