@media (max-width:900px){ .site-product-panel, .site-metric-strip { grid-template-columns:1fr; } }

/* v0.5 docs/product primitives */
.feral-preview-frame {
  position: relative;
  border: var(--feral-border-md) solid var(--feral-ink);
  border-radius: var(--feral-radius-lg);
  background: var(--feral-paper);
  box-shadow: var(--feral-pressure-md) var(--feral-pressure-md) 0 var(--feral-ink);
  overflow: hidden;
}
.feral-preview-title {
  display: inline-flex;
  border-right: var(--feral-border-sm) solid var(--feral-ink);
  border-bottom: var(--feral-border-sm) solid var(--feral-ink);
  background: var(--feral-acid);
  padding: 8px 12px;
  font: 800 12px/1 var(--feral-font-display);
  text-transform: uppercase;
  letter-spacing: .04em;
}
.feral-preview-stage {
  min-height: 180px;
  display: grid;
  place-items: center;
  padding: 28px;
  background-image: radial-gradient(rgba(10,10,10,.18) 1px, transparent 1px);
  background-size: 16px 16px;
}
.feral-code-tabs {
  display: grid;
  gap: 10px;
}
.feral-code-tabs-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}
.feral-code-tabs-buttons {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}
.feral-docs-shell {
  display: grid;
  grid-template-columns: minmax(180px, 260px) minmax(0, 1fr);
  gap: 20px;
  margin-top: 24px;
}
.feral-docs-nav {
  position: sticky;
  top: 74px;
  align-self: start;
  display: grid;
  gap: 8px;
  padding: 12px;
  border: var(--feral-border-md) solid var(--feral-ink);
  background: var(--feral-acid);
  box-shadow: var(--feral-pressure-md) var(--feral-pressure-md) 0 var(--feral-ink);
}
.feral-docs-nav button {
  text-align: left;
  cursor: pointer;
  border: var(--feral-border-sm) solid var(--feral-ink);
  background: var(--feral-paper);
  padding: 10px;
  display: grid;
  gap: 2px;
  font-weight: 800;
}
.feral-docs-nav button[data-active="true"] {
  background: var(--feral-pink);
  color: white;
  transform: rotate(-1deg);
  box-shadow: 3px 3px 0 var(--feral-ink);
}
.feral-docs-nav small {
  font: 700 10px/1 var(--feral-font-monoish);
  text-transform: uppercase;
  opacity: .72;
}
.feral-docs-main {
  min-width: 0;
}
.feral-doc-page {
  display: grid;
  gap: 18px;
}
.feral-doc-page > h3,
.feral-doc-title-row h3 {
  margin: 0;
  font-size: clamp(24px, 3vw, 38px);
  line-height: .95;
  letter-spacing: -.03em;
}
.feral-doc-page p,
.feral-doc-title-row p {
  margin: 8px 0 0;
  max-width: 68ch;
  color: var(--feral-muted);
  line-height: 1.55;
}
.feral-doc-title-row {
  display: flex;
  gap: 16px;
  justify-content: space-between;
  align-items: start;
}
.feral-token-grid {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}
.site-section-head {
  display: flex;
  justify-content: space-between;
  align-items: start;
  gap: 18px;
}
.feral-style-lab {
  display: grid;
  grid-template-columns: minmax(260px, 360px) minmax(0, 1fr);
  gap: 20px;
  margin-top: 26px;
  color: var(--feral-ink);
}
.feral-style-lab-controls {
  align-self: start;
}
.feral-preset-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}
.feral-style-lab-preview {
  position: relative;
  width: min(100%, 620px);
  min-height: 320px;
  display: grid;
  place-items: center;
}
.feral-style-lab-preview .feral-card {
  max-width: 460px;
  z-index: 2;
}
.feral-ornament {
  width: 92px;
  height: 92px;
  fill: var(--feral-acid);
  stroke: var(--feral-ink);
  stroke-width: 5;
  paint-order: stroke fill;
  filter: drop-shadow(4px 4px 0 var(--feral-ink));
}
.feral-ornament-stroke {
  fill: none;
  stroke-width: 8;
  stroke-linecap: round;
  stroke-linejoin: round;
}
.feral-ornament-acid { fill: var(--feral-acid); stroke: var(--feral-ink); color: var(--feral-acid); }
.feral-ornament-pink { fill: var(--feral-pink); stroke: var(--feral-ink); color: var(--feral-pink); }
.feral-ornament-ultra { fill: var(--feral-ultra); stroke: var(--feral-ink); color: var(--feral-ultra); }
.feral-ornament-tang { fill: var(--feral-tang); stroke: var(--feral-ink); color: var(--feral-tang); }
.feral-ornament-cyan { fill: var(--feral-cyan); stroke: var(--feral-ink); color: var(--feral-cyan); }
.feral-ornament-paper { fill: var(--feral-paper); stroke: var(--feral-ink); color: var(--feral-paper); }
.feral-ornament-stroke.feral-ornament-acid,
.feral-ornament-stroke.feral-ornament-pink,
.feral-ornament-stroke.feral-ornament-ultra,
.feral-ornament-stroke.feral-ornament-tang,
.feral-ornament-stroke.feral-ornament-cyan,
.feral-ornament-stroke.feral-ornament-paper { fill: none; stroke: currentColor; }
.feral-style-lab-preview .feral-ornament:nth-child(1) { position: absolute; top: 10px; left: 10px; transform: rotate(-13deg); }
.feral-style-lab-preview .feral-ornament:nth-child(2) { position: absolute; right: 0; bottom: 18px; transform: rotate(12deg); }
.feral-style-lab-preview .feral-ornament:nth-child(3) { position: absolute; right: 30px; top: 18px; width: 130px; transform: rotate(-8deg); }
.feral-stamp {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: fit-content;
  padding: 8px 12px;
  border: var(--feral-border-md) solid var(--feral-ink);
  border-radius: var(--feral-radius-none);
  background: var(--feral-tang);
  box-shadow: 4px 4px 0 var(--feral-ink);
  transform: rotate(-4deg);
  font: 900 13px/1 var(--feral-font-display);
  text-transform: uppercase;
  letter-spacing: .08em;
}
.feral-stamp.feral-ornament-pink { background: var(--feral-pink); color: #fff; }
.feral-stamp.feral-ornament-acid { background: var(--feral-acid); color: var(--feral-ink); }
.feral-stamp.feral-ornament-ultra { background: var(--feral-ultra); color: #fff; }
.feral-stamp.feral-ornament-tang { background: var(--feral-tang); color: var(--feral-ink); }

@media (max-width: 860px) {
  .feral-docs-shell,
  .feral-style-lab {
    grid-template-columns: 1fr;
  }
  .feral-docs-nav {
    position: static;
  }
  .site-section-head {
    display: grid;
  }
}

/* v0.6 routed docs/product architecture */
.route-shell { background: var(--feral-cream); }
.route-nav a[href^="#/"] { border-radius: var(--feral-radius-sm); }
.route-main { max-width: 1180px; margin: 0 auto; padding: 0 20px 72px; }
.route-hero { padding: 72px 0 32px; display: grid; gap: 14px; }
.route-hero h1 { margin: 0; max-width: 980px; font-size: clamp(42px, 7vw, 86px); line-height: .9; letter-spacing: -.055em; }
.route-hero p { margin: 0; max-width: 72ch; color: #322c26; font-size: 18px; line-height: 1.55; font-weight: 650; }
.route-hero-actions { display: flex; gap: 10px; flex-wrap: wrap; align-items: center; }
.route-card-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(230px, 1fr)); gap: 18px; margin: 24px 0 42px; }
.route-card { --feral-shadow-color: var(--feral-ink); display: grid; gap: 10px; align-content: start; min-height: 170px; padding: 18px; border: var(--feral-border-md) solid var(--feral-ink); background: var(--feral-paper); box-shadow: var(--feral-pressure-md) var(--feral-pressure-md) 0 var(--feral-shadow-color); text-decoration: none; }
.route-card[data-tone="acid"] { background: var(--feral-acid); border-radius: var(--feral-radius-none); }
.route-card[data-tone="pink"] { background: var(--feral-pink); color: #fff; --feral-shadow-color: var(--feral-ultra); border-radius: var(--feral-radius-lg); }
.route-card[data-tone="ultra"] { background: var(--feral-ultra); color: #fff; --feral-shadow-color: var(--feral-acid); border-radius: var(--feral-radius-none); }
.route-card strong { display: block; font-size: 22px; line-height: 1; letter-spacing: -.03em; }
.route-card span { color: inherit; opacity: .82; font: 650 13px/1.45 var(--feral-font-monoish); }
.route-two-col { display: grid; grid-template-columns: minmax(0, 1.35fr) minmax(260px, .65fr); gap: 20px; margin: 24px 0; align-items: start; }
.template-full-preview { display: grid; gap: 24px; width: 100%; }
.template-ai { min-height: 520px; }
.ornament-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 16px; margin: 24px 0; }
.ornament-grid .feral-card-content { display: grid; place-items: center; gap: 12px; min-height: 170px; }
.feral-lab-color-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 10px; }
.feral-lab-actions { display: flex; gap: 10px; flex-wrap: wrap; }
.feral-style-lab[data-contrast="high"] { --feral-muted: #18120d; }
.feral-style-lab[data-contrast="quiet"] { --feral-pink: color-mix(in srgb, var(--feral-pink) 68%, white); --feral-acid: color-mix(in srgb, var(--feral-acid) 70%, white); }
.feral-style-lab[data-contrast="grit"] .feral-preview-stage { background-image: radial-gradient(rgba(10,10,10,.28) 1.4px, transparent 1.4px), repeating-linear-gradient(45deg, transparent 0 10px, rgba(10,10,10,.08) 10px 11px); }

/* v0.6 DataTable hardening */
.feral-data-table-wrap { display: grid; gap: 12px; }
.feral-data-table-toolbar, .feral-data-table-footer { display: flex; justify-content: space-between; align-items: center; gap: 12px; flex-wrap: wrap; }
.feral-data-table-toolbar .feral-input { max-width: 360px; }
.feral-data-table-toolbar span, .feral-data-table-footer span { font: 800 12px var(--feral-font-monoish); color: var(--feral-muted); }
.feral-data-table-footer > div { display: flex; gap: 8px; }
.feral-data-table-scroll { overflow-x: auto; border: var(--feral-border-xs) solid var(--feral-ink); background: var(--feral-paper); }
.feral-data-table-sort { display: inline-flex; align-items: center; gap: 8px; width: 100%; padding: 0; border: 0; background: transparent; color: inherit; cursor: pointer; font: inherit; text-align: left; }
.feral-data-table-sort span { display: inline-grid; place-items: center; width: 22px; height: 22px; border: var(--feral-border-xs) solid var(--feral-ink); background: var(--feral-acid); box-shadow: 2px 2px 0 var(--feral-ink); }
.feral-data-table-select { width: 42px; text-align: center; }
.feral-data-table-select input { width: 20px; height: 20px; accent-color: var(--feral-pink); }
.feral-table-row[data-selected="true"] .feral-table-cell { background: color-mix(in srgb, var(--feral-acid) 48%, white); }
.feral-data-table-empty { padding: 24px; text-align: center; font-weight: 900; }
.feral-data-table-skeleton { display: block; width: 100%; height: 18px; border: var(--feral-border-xs) solid var(--feral-ink); background: repeating-linear-gradient(90deg, var(--feral-paper) 0 12px, var(--feral-acid) 12px 22px); }
.feral-data-table-dense .feral-table-cell, .feral-data-table-dense .feral-table-head { padding: 8px 10px; font-size: 12px; }
@media (max-width: 720px) { [data-hide-mobile="true"] { display: none; } .route-two-col { grid-template-columns: 1fr; } .route-main { padding-inline: 14px; } }

/* v0.6 ornament expansion */
.feral-ornament-sm { width: 52px; height: 52px; }
.feral-ornament-md { width: 92px; height: 92px; }
.feral-ornament-lg { width: 128px; height: 128px; }
.feral-ornament-xl { width: 180px; height: 180px; }
.feral-ornament-ink { fill: var(--feral-ink); stroke: var(--feral-ink); color: var(--feral-cream); }
.feral-ornament-verm { fill: var(--feral-verm); stroke: var(--feral-ink); color: var(--feral-verm); }
.feral-stamp.feral-ornament-ink { background: var(--feral-ink); color: var(--feral-cream); }
.feral-stamp.feral-ornament-verm { background: var(--feral-verm); color: #fff; }
.feral-stamp.feral-ornament-paper { background: var(--feral-paper); color: var(--feral-ink); border-style: dashed; }

@media (max-width: 860px) {
  .route-card-grid { grid-template-columns: 1fr; }
  .feral-lab-color-grid { grid-template-columns: 1fr; }
}

/* v0.7 hardening pass: calendar range, toasts, carousel controls, sidebar behavior */
.feral-calendar-day:disabled { cursor:not-allowed; opacity:.28; background:#e8dfd1; box-shadow:none; }
.feral-calendar-day[data-in-range="true"] { background:var(--feral-acid); }
.feral-calendar-day[data-range-start="true"], .feral-calendar-day[data-range-end="true"] { background:var(--feral-pink); color:#fff; box-shadow:3px 3px 0 var(--feral-ink); }
.feral-date-range-popover { min-width:min(360px, calc(100vw - 32px)); }
.feral-date-range-note { margin:10px 0 0; font:800 12px var(--feral-font-monoish); color:#443b33; }
.feral-toast { grid-template-columns:minmax(0,1fr) auto; align-items:start; }
.feral-toast[data-tone="pink"] { background:var(--feral-pink); color:#fff; box-shadow:5px 5px 0 var(--feral-ultra); }
.feral-toast[data-tone="ultra"] { background:var(--feral-ultra); color:#fff; box-shadow:5px 5px 0 var(--feral-acid); }
.feral-toast[data-tone="paper"] { background:var(--feral-paper); }
.feral-toast[data-tone="danger"] { background:var(--feral-verm); color:#fff; box-shadow:5px 5px 0 var(--feral-ink); }
.feral-toast-copy { display:grid; gap:3px; }
.feral-toast-actions { display:flex; gap:6px; align-items:start; }
.feral-toast-close { width:30px; height:30px; display:grid; place-items:center; border:var(--feral-border-xs) solid var(--feral-ink); background:#fff; color:var(--feral-ink); box-shadow:3px 3px 0 var(--feral-ink); cursor:pointer; }
.feral-carousel { display:grid; gap:0; }
.feral-carousel-track:focus-visible { outline:3px dashed var(--feral-ultra); outline-offset:-8px; }
.feral-carousel-controls { display:flex; align-items:center; justify-content:space-between; gap:10px; padding:10px 14px; border-top:var(--feral-border-xs) solid var(--feral-ink); background:var(--feral-acid); font:900 12px var(--feral-font-display); }
.feral-carousel-controls .feral-button:disabled { opacity:.45; cursor:not-allowed; transform:none; }
.feral-carousel-dots { display:flex; justify-content:center; gap:8px; padding:0 14px 14px; }
.feral-carousel-dots button { width:14px; height:14px; border:var(--feral-border-xs) solid var(--feral-ink); border-radius:999px; background:#fff; box-shadow:2px 2px 0 var(--feral-ink); cursor:pointer; }
.feral-carousel-dots button[aria-current="true"] { background:var(--feral-pink); transform:translate(2px,2px); box-shadow:0 0 0 var(--feral-ink); }
.feral-sidebar-layout[data-collapsed="true"] { grid-template-columns:82px minmax(0,1fr); }
.feral-sidebar-layout[data-collapsed="true"] .feral-sidebar { align-items:stretch; }
.feral-sidebar-layout[data-collapsed="true"] .feral-sidebar-section h3,
.feral-sidebar-layout[data-collapsed="true"] .feral-sidebar-link-label,
.feral-sidebar-layout[data-collapsed="true"] .feral-sidebar-footer { display:none; }
.feral-sidebar-toggle { display:none; width:max-content; margin:12px; }
.feral-sidebar-section { display:grid; gap:8px; }
.feral-sidebar-section h3 { margin:8px 0 0; font:900 11px var(--feral-font-monoish); text-transform:uppercase; letter-spacing:.08em; color:#342b26; }
.feral-sidebar-footer { margin-top:auto; border-top:var(--feral-border-xs) solid var(--feral-ink); padding-top:12px; font:800 12px var(--feral-font-monoish); }
.feral-sidebar-link { display:flex; align-items:center; gap:8px; }
.feral-sidebar-link-icon { display:inline-grid; place-items:center; width:24px; height:24px; border:var(--feral-border-xs) solid var(--feral-ink); background:#fff; color:var(--feral-ink); flex:none; }
@media (max-width: 900px) {
  .feral-sidebar-toggle { display:inline-flex; }
  .feral-sidebar-layout { position:relative; display:block; overflow:hidden; }
  .feral-sidebar { display:none; border-right:0; border-bottom:var(--feral-border-sm) solid var(--feral-ink); }
  .feral-sidebar-layout[data-mobile-open="true"] .feral-sidebar { display:flex; }
}
